import{_ as t,o as a,c as o,ad as i}from"./chunks/framework.DdcUsuRQ.js";const m=JSON.parse('{"title":"Hex","description":"The","frontmatter":{"title":"Hex","description":"The","head":[["link",{"rel":"canonical","href":"https://studnicky.github.io/iridis/reference/hex"}],["meta",{"property":"og:url","content":"https://studnicky.github.io/iridis/reference/hex"}],["meta",{"property":"og:title","content":"Hex: iridis"}],["meta",{"property":"og:description","content":"The"}],["meta",{"name":"twitter:title","content":"Hex: iridis"}],["meta",{"name":"twitter:description","content":"The"}],["meta",{"name":"description","content":"The"}],["meta",{"property":"article:modified_time","content":"2026-05-17T03:59:59.000Z"}],["meta",{"property":"article:author","content":"Andrew Studnicky"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"iridis\\",\\"item\\":\\"https://studnicky.github.io/iridis/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Reference\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"Hex\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference/hex\\"}]}"]]},"headers":[],"relativePath":"reference/hex.md","filePath":"reference/hex.md","lastUpdated":1778990399000}'),r={name:"reference/hex.md"};function s(n,e,d,c,h,p){return a(),o("div",null,[...e[0]||(e[0]=[i(`<h1 id="hex" tabindex="-1">Hex <a class="header-anchor" href="#hex" aria-label="Permalink to &quot;Hex&quot;">​</a></h1><p>A hex color is an sRGB triple encoded as three or four bytes in hexadecimal.</p><h2 id="syntax" tabindex="-1">Syntax <a class="header-anchor" href="#syntax" aria-label="Permalink to &quot;Syntax&quot;">​</a></h2><p><span class="iridis-brand">iridis</span> accepts two forms:</p><table tabindex="0"><thead><tr><th>Form</th><th>Bytes</th><th>Channels</th></tr></thead><tbody><tr><td><code>#rrggbb</code></td><td>3</td><td>red, green, blue</td></tr><tr><td><code>#rrggbbaa</code></td><td>4</td><td>red, green, blue, alpha</td></tr></tbody></table><p>The leading <code>#</code> is optional in user input but the canonical stored form keeps it. Each byte ranges <code>00</code>-<code>ff</code> (0-255). Case is normalised to lower-case on storage.</p><p>The three-digit shorthand <code>#rgb</code> and the four-digit <code>#rgba</code> are not accepted. Anything other than six or eight hexadecimal characters after the optional <code>#</code> is rejected.</p><h2 id="conversion" tabindex="-1">Conversion <a class="header-anchor" href="#conversion" aria-label="Permalink to &quot;Conversion&quot;">​</a></h2><p>A hex string converts to floating-point sRGB by reading each byte and dividing by 255. Alpha follows the same rule when present, otherwise defaults to 1.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes iridis iridis vp-code" tabindex="0"><code><span class="line"><span>r = parseInt(hex[0:2], 16) / 255</span></span>
<span class="line"><span>g = parseInt(hex[2:4], 16) / 255</span></span>
<span class="line"><span>b = parseInt(hex[4:6], 16) / 255</span></span>
<span class="line"><span>a = hex.length === 8 ? parseInt(hex[6:8], 16) / 255 : 1</span></span></code></pre></div><p>The reverse direction multiplies each channel by 255, rounds, and pads to two hexadecimal digits. The canonical hex written back from a <code>ColorRecord</code> is always six digits, alpha lives in the <code>alpha</code> field, not in the hex string.</p><h2 id="math-primitives" tabindex="-1">Math primitives <a class="header-anchor" href="#math-primitives" aria-label="Permalink to &quot;Math primitives&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Primitive</th><th>File</th><th>Behaviour</th></tr></thead><tbody><tr><td><code>hexToRgb</code></td><td><code>packages/core/src/math/HexToRgb.ts</code></td><td>parses a hex string and returns a full <code>ColorRecord</code> via <code>ColorRecordFactory.fromHex</code></td></tr><tr><td><code>rgbToHex</code></td><td><code>packages/core/src/math/RgbToHex.ts</code></td><td>writes three sRGB channels as <code>#rrggbb</code></td></tr></tbody></table><p><code>ColorRecordFactory.fromHex</code> (<code>packages/core/src/math/ColorRecordFactory.ts</code>) holds the validation regex <code>^[0-9a-fA-F]{6}([0-9a-fA-F]{2})?$</code> and the alpha extraction logic. It populates the OKLCH coordinates by routing the parsed sRGB through the same path <code>fromRgb</code> uses, so a record built from hex is interchangeable with one built from any other intake.</p><h2 id="where-it-appears" tabindex="-1">Where it appears <a class="header-anchor" href="#where-it-appears" aria-label="Permalink to &quot;Where it appears&quot;">​</a></h2><ul><li><code>intake:hex</code> (<code>packages/core/src/tasks/intake/IntakeHex.ts</code>) consumes hex strings from <code>input.colors</code> and produces <code>ColorRecord</code> entries.</li><li><code>intake:any</code> dispatches hex inputs to <code>intake:hex</code>.</li><li><code>emit:cssVars</code> and the stylesheet plugin write hex back out as the default serialised form.</li><li>The visual picker (<code>docs/.vitepress/theme/components/IridisPicker.vue</code>) round-trips hex on every edit through HSV → RGB → hex.</li></ul>`,16)])])}const u=t(r,[["render",s]]);export{m as __pageData,u as default};
